DefaultCurrency9156.isReadOnly = function(){return true;}
DefaultCurrency9156.isTemporary = function(){return true;}
DefaultCurrency9156.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9156.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
